# Use a small C# script to reflect over the assembly
cd /tmp/sv-d2830c0710f548af97ca6b7ec4be4ca3/ResearchAgent
cat > /tmp/reflect.cs << 'CSHARP'
using System.Reflection;

var dll = "/home/runner/.nuget/packages/microsoft.agents.ai/1.0.0/lib/net10.0/Microsoft.Agents.AI.dll";
var asm = Assembly.LoadFrom(dll);

foreach (var type in asm.GetExportedTypes().OrderBy(t => t.FullName))
{
    Console.WriteLine($"\n=== {type.FullName} ===");
    if (type.BaseType != null && type.BaseType != typeof(object))
        Console.WriteLine($"  Base: {type.BaseType.Name}");
    foreach (var iface in type.GetInterfaces().Where(i => i.IsPublic))
        Console.WriteLine($"  Implements: {iface.Name}");
    foreach (var ctor in type.GetConstructors())
        Console.WriteLine($"  ctor({string.Join(", ", ctor.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
    foreach (var prop in type.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
        Console.WriteLine($"  {prop.PropertyType.Name} {prop.Name} {{ {(prop.CanRead?"get;":"")}{(prop.CanWrite?" set;":"")} }}");
    foreach (var method in type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly)
        .Where(m => !m.IsSpecialName))
        Console.WriteLine($"  {method.ReturnType.Name} {method.Name}({string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
}
CSHARP
