using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using System.Text.RegularExpressions;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search and page fetching capabilities for the research agent.
/// Uses DuckDuckGo Instant Answer API (no API key required).
/// </summary>
public sealed partial class WebSearchTool
{
    private readonly HttpClient _httpClient;

    public WebSearchTool(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    [Description("Searches the web for a query and returns a list of result titles, snippets, and URLs.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query to look up")] string query,
        CancellationToken cancellationToken = default)
    {
        var encodedQuery = Uri.EscapeDataString(query);
        var url = $"https://api.duckduckgo.com/?q={encodedQuery}&format=json&no_html=1&skip_disambig=1";

        var doc = await _httpClient.GetFromJsonAsync<JsonElement>(url, cancellationToken);

        var results = new List<string>();

        // Abstract (main topic summary)
        var abstractText = doc.GetProperty("AbstractText").GetString();
        var abstractSource = doc.GetProperty("AbstractSource").GetString();
        var abstractUrl = doc.GetProperty("AbstractURL").GetString();
        if (!string.IsNullOrWhiteSpace(abstractText))
        {
            results.Add($"[{abstractSource}] {abstractText}\n  URL: {abstractUrl}");
        }

        // Related topics
        if (doc.TryGetProperty("RelatedTopics", out var relatedTopics))
        {
            foreach (var topic in relatedTopics.EnumerateArray().Take(8))
            {
                var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
                var firstUrl = topic.TryGetProperty("FirstURL", out var u) ? u.GetString() : null;
                if (!string.IsNullOrWhiteSpace(text))
                {
                    results.Add($"- {text}\n  URL: {firstUrl}");
                }
            }
        }

        // Infobox
        if (doc.TryGetProperty("Infobox", out var infobox)
            && infobox.ValueKind == JsonValueKind.Object
            && infobox.TryGetProperty("content", out var content))
        {
            foreach (var item in content.EnumerateArray().Take(6))
            {
                var label = item.TryGetProperty("label", out var l) ? l.GetString() : null;
                var value = item.TryGetProperty("value", out var v) ? v.GetString() : null;
                if (label is not null && value is not null)
                {
                    results.Add($"  {label}: {value}");
                }
            }
        }

        return results.Count > 0
            ? string.Join("\n\n", results)
            : $"No instant results found for '{query}'. Try fetching a specific URL or rephrasing the query.";
    }

    [Description("Fetches the text content of a web page at the given URL. Returns the first ~4000 characters of readable text.")]
    public async Task<string> FetchWebPageAsync(
        [Description("The full URL of the web page to fetch")] string url,
        CancellationToken cancellationToken = default)
    {
        try
        {
            var response = await _httpClient.GetAsync(url, cancellationToken);
            response.EnsureSuccessStatusCode();
            var html = await response.Content.ReadAsStringAsync(cancellationToken);

            var text = StripHtml(html);
            const int maxLength = 4000;
            if (text.Length > maxLength)
            {
                text = text[..maxLength] + "\n\n[Content truncated]";
            }

            return string.IsNullOrWhiteSpace(text)
                ? "Page returned no readable text content."
                : text;
        }
        catch (HttpRequestException ex)
        {
            return $"Failed to fetch URL: {ex.Message}";
        }
    }

    private static string StripHtml(string html)
    {
        // Remove script and style blocks
        var cleaned = ScriptStyleRegex().Replace(html, " ");
        // Remove HTML tags
        cleaned = TagRegex().Replace(cleaned, " ");
        // Decode common entities
        cleaned = cleaned
            .Replace("&amp;", "&")
            .Replace("&lt;", "<")
            .Replace("&gt;", ">")
            .Replace("&quot;", "\"")
            .Replace("&#39;", "'")
            .Replace("&nbsp;", " ");
        // Collapse whitespace
        cleaned = WhitespaceRegex().Replace(cleaned, " ").Trim();
        return cleaned;
    }

    [GeneratedRegex(@"<(script|style)[^>]*>[\s\S]*?</\1>", RegexOptions.IgnoreCase)]
    private static partial Regex ScriptStyleRegex();

    [GeneratedRegex(@"<[^>]+>")]
    private static partial Regex TagRegex();

    [GeneratedRegex(@"\s{2,}")]
    private static partial Regex WhitespaceRegex();
}

using System.ComponentModel;

namespace ResearchAgent.Tools;

/// <summary>
/// In-memory note-taking tool that lets the agent record and retrieve research findings.
/// </summary>
public sealed class NoteTool
{
    private readonly List<(string Title, string Content, DateTime Timestamp)> _notes = [];

    [Description("Saves a research note. Use this to record key findings, facts, or quotes discovered during research.")]
    public string AddNote(
        [Description("A short title for the note")] string title,
        [Description("The detailed content of the note")] string content)
    {
        _notes.Add((title, content, DateTime.UtcNow));
        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    [Description("Retrieves all research notes taken so far. Use this before writing a final summary.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes have been taken yet.";
        }

        var lines = _notes.Select((n, i) =>
            $"--- Note #{i + 1}: {n.Title} ---\n{n.Content}");
        return string.Join("\n\n", lines);
    }

    [Description("Returns the total number of notes taken so far.")]
    public string GetNoteCount()
    {
        return $"{_notes.Count} note(s) recorded.";
    }
}

