+/// <summary>
+/// In-memory note-taking tool that lets the agent record and retrieve research findings.
+/// </summary>
+public sealed class NoteTool
+{
+    private readonly List<(string Title, string Content, DateTime Timestamp)> _notes = [];
+
+    [Description("Saves a research note. Use this to record key findings, facts, or quotes discovered during research.")]
+    public string AddNote(
+        [Description("A short title for the note")] string title,
+        [Description("The detailed content of the note")] string content)
+    {
+        _notes.Add((title, content, DateTime.UtcNow));
+        return $"Note #{_notes.Count} saved: \"{title}\"";
+    }
+
+    [Description("Retrieves all research notes taken so far. Use this before writing a final summary.")]
+    public string GetAllNotes()
+    {
+        if (_notes.Count == 0)
+        {
+            return "No notes have been taken yet.";
+        }
+
+        var lines = _notes.Select((n, i) =>
+            $"--- Note #{i + 1}: {n.Title} ---\n{n.Content}");
+        return string.Join("\n\n", lines);
+    }
+
+    [Description("Returns the total number of notes taken so far.")]
+    public string GetNoteCount()
+    {
+        return $"{_notes.Count} note(s) recorded.";
+    }
+}
