 using Microsoft.Extensions.AI;
 using Microsoft.Agents.AI;
 using OpenAI;
 using ResearchAgent.Tools;

 // --- Configuration ---

 var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
     ?? throw new InvalidOperationException(
         "Set the OPENAI_API_KEY environment variable before running this app.");

 var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

 // --- Build the IChatClient ---

 IChatClient chatClient = new OpenAIClient(apiKey)
     .GetChatClient(modelId)
     .AsIChatClient();

 // --- Create tools ---

 using var httpClient = new HttpClient();
 httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
 httpClient.Timeout = TimeSpan.FromSeconds(15);

 var webSearch = new WebSearchTool(httpClient);
 var noteTool = new NoteTool();

 var tools = new AITool[]
 {
     AIFunctionFactory.Create(webSearch.SearchWebAsync),
     AIFunctionFactory.Create(webSearch.FetchWebPageAsync),
     AIFunctionFactory.Create(noteTool.AddNote),
     AIFunctionFactory.Create(noteTool.GetAllNotes),
     AIFunctionFactory.Create(noteTool.GetNoteCount),
 };

 // --- Build the ChatClientAgent ---

 const string instructions = """
     You are a thorough research agent. Your goal is to research the user's topic
     and produce a well-organized summary of your findings.

     Follow this workflow:
     1. Search the web for the topic using multiple queries to cover different angles.
     2. Fetch promising web pages for deeper detail when search snippets aren't enough.
     3. Take notes on every key finding — record facts, statistics, quotes, and source URLs.
     4. Once you've gathered enough information (aim for at least 3-5 notes), retrieve
        all your notes and write a comprehensive summary.

     Your final summary should include:
     - An overview of the topic
     - Key facts and details organized by sub-topic
     - Source URLs for attribution

     Be factual, cite your sources, and avoid speculation.
     """;

 var agent = new ChatClientAgent(
     chatClient,
     instructions: instructions,
     name: "ResearchAgent",
     description: "An AI agent that researches topics by searching the web and taking notes.",
     tools: tools);

 var runOptions = new ChatClientAgentRunOptions(new ChatOptions
 {
     Temperature = 0f,
     MaxOutputTokens = 4096,
 });

 // --- Get topic from user ---

 Console.ForegroundColor = ConsoleColor.Cyan;
 Console.WriteLine("╔══════════════════════════════════════════╗");
 Console.WriteLine("║       AI Research Agent                  ║");
 Console.WriteLine("╚══════════════════════════════════════════╝");
 Console.ResetColor();
 Console.WriteLine();

 Console.Write("Enter a research topic: ");
 var topic = Console.ReadLine()?.Trim();
 if (string.IsNullOrWhiteSpace(topic))
 {
     Console.WriteLine("No topic provided. Exiting.");
     return;
 }

 Console.WriteLine();
 Console.ForegroundColor = ConsoleColor.DarkGray;
 Console.WriteLine($"Researching: {topic}");
 Console.WriteLine("(The agent will search the web, take notes, and produce a summary...)\n");
 Console.ResetColor();

 // --- Run the agent with streaming ---

 await foreach (var update in agent.RunStreamingAsync(
     $"Research this topic thoroughly: {topic}",
     options: runOptions))
 {
     if (update.Text is { Length: > 0 } text)
     {
         Console.Write(text);
     }
 }

